# use nom::{Err, error::ErrorKind, Needed, IResult, Parser};
use nom::number::complete::be_u16;
use nom::multi::length_data;
use nom::bytes::complete::tag;

fn parser(s: &[u8]) -> IResult<&[u8], &[u8]> {
length_data(be_u16).parse(s)
